old_string:
/* VurgLife logo watermark — horizontal across the felt */
/* PNG is white-on-black. mix-blend-mode:screen makes black invisible,
   white shows through as a clean watermark on any dark background */
.table-logo {
  position: absolute;
  top: 46%; left: 50%;
  transform: translate(-50%, -50%);
  width: clamp(360px, 62%, 580px);
  opacity: 0.22;
  pointer-events: none;
  z-index: 2;
  user-select: none;
  mix-blend-mode: screen;   /* black = transparent, white = visible */
  filter: brightness(0.85);
}

new_string:
/* VurgLife logo watermark — horizontal across the felt, BEHIND all gameplay */
/* PNG is white-on-black. mix-blend-mode:screen makes black invisible,
   white shows through as a clean watermark on any dark background */
.table-logo {
  position: absolute;
  top: 46%; left: 50%;
  transform: translate(-50%, -50%);
  width: clamp(360px, 62%, 580px);
  opacity: 0.22;
  pointer-events: none;
  /* z-index:-1 inside .oval-table's isolated stacking context puts the
     watermark behind cards, placeholders, win/lose labels, etc. */
  z-index: -1;
  user-select: none;
  mix-blend-mode: screen;   /* black = transparent, white = visible */
  filter: brightness(0.85);
}

